import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { useAuthStore } from '../store/auth';
import { useTheme } from '../config/theme';

interface LoginFormProps {
  onSwitchToRegister: () => void;
}

const LoginForm: React.FC<LoginFormProps> = ({ onSwitchToRegister }) => {
  const theme = useTheme();
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [googleLoading, setGoogleLoading] = useState(false);
  const { login, isLoading, error, clearError } = useAuthStore();

  if (!theme) {
    return <div className="max-w-md mx-auto bg-white rounded-lg shadow-md p-6">Cargando...</div>;
  }

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    clearError();

    try {
      await login(email, password);
    } catch (error) {
      // Error ya manejado en el store
    }
  };

  const handleGoogleLogin = async () => {
    clearError();

    try {
      // Crear un popup para Google Auth usando el endpoint correcto y URLSearchParams
      const clientId = import.meta.env.VITE_GOOGLE_CLIENT_ID;
      if (!clientId) {
        throw new Error('VITE_GOOGLE_CLIENT_ID no está configurado');
      }

      const params = new URLSearchParams({
        client_id: clientId,
        redirect_uri: `${window.location.origin}/auth/google/callback`,
        response_type: 'code',
        scope: 'openid email profile',
        access_type: 'offline',
        include_granted_scopes: 'true',
        prompt: 'consent',
      });

      const googleAuthUrl = `https://accounts.google.com/o/oauth2/v2/auth?${params.toString()}`;

      // Abrir popup de Google Auth
      const popup = window.open(googleAuthUrl, 'googleAuth', 'width=500,height=600');

      if (!popup) {
        throw new Error('No se pudo abrir la ventana de Google Auth');
      }

      setGoogleLoading(true);

      // Escuchar el mensaje del popup
      const messageListener = (event: MessageEvent) => {
        console.log('[GoogleAuth] Mensaje recibido del popup:', event);
        if (event.origin !== window.location.origin) {
          console.warn('[GoogleAuth] Origen no coincide, ignorando mensaje:', event.origin);
          return;
        }

        if (event.data.type === 'GOOGLE_AUTH_SUCCESS') {
          const { authData } = event.data;
          // Establecer sesión usando el store (Zustand + persist)
          // Esto asegura que el interceptor de Axios lea correctamente 'auth-storage'
          try {
            // Actualizar estado global de autenticación
            (useAuthStore as any).setState({
              user: authData.user,
              token: authData.token,
              isAuthenticated: true,
              isLoading: false,
              error: null,
            });
          } finally {
            setGoogleLoading(false);
            popup.close();
            window.removeEventListener('message', messageListener);
          }
        } else if (event.data.type === 'GOOGLE_AUTH_ERROR') {
          console.error('[GoogleAuth] Error recibido del popup:', event.data?.error);
          // Reflejar el error en el formulario
          (useAuthStore as any).setState({
            error: event.data?.error || 'Error en autenticación con Google',
            isLoading: false,
          });
          setGoogleLoading(false);
          popup.close();
          window.removeEventListener('message', messageListener);
        }
      };

      window.addEventListener('message', messageListener);

      // Cerrar popup si se cierra manualmente
      const checkClosed = setInterval(() => {
        if (popup.closed) {
          clearInterval(checkClosed);
          window.removeEventListener('message', messageListener);
          // Si se cerró sin mensaje, cancelar loading
          setGoogleLoading(false);
        }
      }, 1000);

    } catch (error: any) {
      // Error ya manejado en el store
      console.error('[GoogleAuth] Error al iniciar flujo:', error);
      (useAuthStore as any).setState({
        error: error?.message || 'No se pudo iniciar Google Auth',
        isLoading: false,
      });
      setGoogleLoading(false);
    }
  };

  return (
    <div className="max-w-md mx-auto bg-white rounded-lg shadow-md p-6">
      <div className="flex items-center justify-center p-4 rounded-lg">
        <img
          src={theme.logoAlt || theme.logo}
          alt={`${theme.companyName} Logo`}
          className="h-24"
        />
      </div>

      <h2 className="text-2xl font-bold text-center mb-6 text-gray-800">
        Iniciar Sesión
      </h2>

      <form onSubmit={handleSubmit} className="space-y-4">
        <div>
          <label htmlFor="email" className="block text-sm font-medium text-gray-700 mb-1">
            Email
          </label>
          <input
            type="email"
            id="email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            required
            className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
            placeholder="tu@email.com"
          />
        </div>

        <div>
          <label htmlFor="password" className="block text-sm font-medium text-gray-700 mb-1">
            Contraseña
          </label>
          <input
            type="password"
            id="password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            required
            className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
            placeholder="••••••••"
          />
        </div>

        <button
          type="submit"
          disabled={isLoading}
          className="w-full bg-blue-600 text-white py-2 px-4 rounded-md hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-blue-500 disabled:opacity-50 disabled:cursor-not-allowed"
        >
          {isLoading ? 'Iniciando sesión...' : 'Iniciar Sesión'}
        </button>
        {error && (
          <div className="mb-4 p-3 bg-red-100 border border-red-400 text-red-700 rounded">
            {error}
          </div>
        )}
      </form>

      <div className="mt-6">
        <div className="relative">
          <div className="absolute inset-0 flex items-center">
            <div className="w-full border-t border-gray-300" />
          </div>
          <div className="relative flex justify-center text-sm">
            <span className="px-2 bg-white text-gray-500">O continuar con</span>
          </div>
        </div>

        {import.meta.env.VITE_GOOGLE_CLIENT_ID && (
          <button
            onClick={handleGoogleLogin}
            disabled={isLoading || googleLoading}
            className="mt-4 w-full flex items-center justify-center px-4 py-2 border border-gray-300 rounded-md shadow-sm bg-white text-sm font-medium text-gray-700 hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-blue-500 disabled:opacity-50"
          >
            <svg className="w-5 h-5 mr-2" viewBox="0 0 24 24">
              <path fill="#4285F4" d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" />
              <path fill="#34A853" d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" />
              <path fill="#FBBC05" d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" />
              <path fill="#EA4335" d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" />
            </svg>
            {isLoading || googleLoading ? 'Conectando...' : 'Continuar con Google'}
          </button>
        )}
      </div>

      <div className="mt-6 text-center">
        <p className="text-sm text-gray-600">
          ¿No tienes cuenta?{' '}
          <button
            onClick={onSwitchToRegister}
            className="text-blue-600 hover:text-blue-500 font-medium"
          >
            Regístrate aquí
          </button>
        </p>
        <p className="mt-2 text-sm text-gray-600">
          ¿Olvidaste tu contraseña?{' '}
          <Link
            to="/forgot-password"
            className="text-blue-600 hover:text-blue-500 font-medium"
          >
            Recupérala aquí
          </Link>
        </p>
      </div>
    </div>
  );
};

export default LoginForm;
